		SELECT COUNT(*)
        FROM questions
        WHERE id = #{questionId}
          AND writer_id = #{userId}
          AND delflag = 'N'

SELECT COUNT(*)
FROM questions q
WHERE q.id = #{questionId}
  AND q.delflag = 'N'
  AND (
      q.visibility = 'PUBLIC'
      OR EXISTS (
          SELECT 1 FROM team_members tm
          WHERE tm.team_id = q.team_id
            AND tm.user_id = #{userId}
            AND tm.delflag = 'N'
      )
  )
